import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  if (!user) return null;

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <Link to="/" className="navbar-brand">
          Store Rating System
        </Link>
        <div className="navbar-menu">
          <span className="user-name">Welcome, {user.name}</span>
          
          {user.role === 'admin' && (
            <>
              <Link to="/admin/dashboard" className="navbar-item">Dashboard</Link>
              <Link to="/admin/users" className="navbar-item">Users</Link>
              <Link to="/admin/stores" className="navbar-item">Stores</Link>
              <Link to="/admin/add-user" className="navbar-item">Add User</Link>
            </>
          )}
          
          {user.role === 'user' && (
            <>
              <Link to="/user/stores" className="navbar-item">Browse Stores</Link>
              <Link to="/user/change-password" className="navbar-item">Change Password</Link>
            </>
          )}
          
          {user.role === 'owner' && (
            <>
              <Link to="/owner/dashboard" className="navbar-item">Dashboard</Link>
              <Link to="/user/change-password" className="navbar-item">Change Password</Link>
            </>
          )}
          
          <button onClick={handleLogout} className="btn btn-danger">Logout</button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
